import type { ThresholdMarker } from '../types.js';

export function sizeOfMarker(marker: ThresholdMarker): number {
  return Math.abs(marker.y1 - marker.y0);
}

export function sortMarkers(
  marker1: ThresholdMarker,
  marker2: ThresholdMarker,
): number {
  return sizeOfMarker(marker2) - sizeOfMarker(marker1);
}
